<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width, initial-scale=1.0"/>
<title>BRITON | Frontend Developer & IT Professional</title>
<link href="https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700&family=DM+Mono:wght@400;500&display=swap" rel="stylesheet"/>
<style>
*{margin:0;padding:0;box-sizing:border-box;}
:root{
  --bg:#0a0a0f;
  --bg2:#111118;
  --bg3:#1a1a24;
  --accent:#00e5a0;
  --accent2:#7c5cfc;
  --text:#e8e8f0;
  --muted:#8888a0;
  --border:#2a2a3a;
  --card:#14141e;
  --white:#ffffff;
}
html{scroll-behavior:smooth;}
body{background:var(--bg);color:var(--text);font-family:'Space Grotesk',sans-serif;overflow-x:hidden;}

/* NAV */
nav{position:fixed;top:0;left:0;right:0;z-index:1000;background:rgba(10,10,15,0.92);backdrop-filter:blur(16px);border-bottom:1px solid var(--border);padding:0 2rem;}
.nav-inner{max-width:1200px;margin:0 auto;display:flex;align-items:center;justify-content:space-between;height:64px;}
.logo{font-size:1.4rem;font-weight:700;color:var(--accent);letter-spacing:-0.02em;text-decoration:none;}
.logo span{color:var(--text);}
.nav-links{display:flex;gap:2rem;list-style:none;}
.nav-links a{color:var(--muted);text-decoration:none;font-size:0.9rem;font-weight:500;transition:color 0.2s;}
.nav-links a:hover{color:var(--accent);}
.nav-cta{background:var(--accent);color:#0a0a0f;padding:0.5rem 1.25rem;border-radius:6px;text-decoration:none;font-weight:600;font-size:0.85rem;transition:opacity 0.2s;}
.nav-cta:hover{opacity:0.85;}
.hamburger{display:none;flex-direction:column;gap:5px;cursor:pointer;background:none;border:none;padding:4px;}
.hamburger span{width:22px;height:2px;background:var(--text);display:block;transition:all 0.3s;}
.mobile-menu{display:none;position:fixed;top:64px;left:0;right:0;background:rgba(10,10,15,0.98);padding:1.5rem 2rem;border-bottom:1px solid var(--border);z-index:999;}
.mobile-menu a{display:block;padding:0.75rem 0;color:var(--muted);text-decoration:none;font-size:1rem;border-bottom:1px solid var(--border);}
.mobile-menu a:hover{color:var(--accent);}

/* HERO */
#home{min-height:100vh;display:flex;align-items:center;padding-top:64px;position:relative;overflow:hidden;}
.hero-bg{position:absolute;inset:0;background:radial-gradient(ellipse 80% 60% at 70% 50%,rgba(0,229,160,0.07) 0%,transparent 65%),radial-gradient(ellipse 50% 40% at 20% 80%,rgba(124,92,252,0.08) 0%,transparent 60%);}
.hero-inner{max-width:1200px;margin:0 auto;padding:4rem 2rem;display:grid;grid-template-columns:1fr 1fr;gap:4rem;align-items:center;width:100%;position:relative;}
.hero-label{display:inline-flex;align-items:center;gap:8px;background:rgba(0,229,160,0.1);border:1px solid rgba(0,229,160,0.25);border-radius:20px;padding:0.35rem 0.9rem;font-size:0.8rem;color:var(--accent);font-weight:500;margin-bottom:1.25rem;}
.hero-label::before{content:'';width:6px;height:6px;border-radius:50%;background:var(--accent);animation:pulse 2s infinite;}
@keyframes pulse{0%,100%{opacity:1;}50%{opacity:0.4;}}
.hero h1{font-size:clamp(2.4rem,5vw,3.8rem);font-weight:700;line-height:1.08;letter-spacing:-0.03em;margin-bottom:1.25rem;}
.hero h1 .name{color:var(--accent);}
.hero h1 .role{color:var(--muted);font-weight:300;}
.hero-desc{color:var(--muted);font-size:1.05rem;line-height:1.7;margin-bottom:2rem;max-width:480px;}
.hero-btns{display:flex;gap:1rem;flex-wrap:wrap;}
.btn-primary{background:var(--accent);color:#0a0a0f;padding:0.8rem 1.75rem;border-radius:8px;text-decoration:none;font-weight:700;font-size:0.95rem;transition:transform 0.2s,opacity 0.2s;display:inline-flex;align-items:center;gap:8px;}
.btn-primary:hover{opacity:0.88;transform:translateY(-1px);}
.btn-outline{border:1px solid var(--border);color:var(--text);padding:0.8rem 1.75rem;border-radius:8px;text-decoration:none;font-weight:500;font-size:0.95rem;transition:border-color 0.2s,background 0.2s;display:inline-flex;align-items:center;gap:8px;}
.btn-outline:hover{border-color:var(--accent);color:var(--accent);}
.hero-img{position:relative;}
.hero-img img{width:100%;border-radius:16px;object-fit:cover;aspect-ratio:4/5;display:block;border:1px solid var(--border);}
.hero-img::before{content:'';position:absolute;inset:-2px;border-radius:18px;background:linear-gradient(135deg,var(--accent),var(--accent2));z-index:-1;opacity:0.4;}
.hero-stats{display:flex;gap:2rem;margin-top:2rem;}
.stat{text-align:left;}
.stat-num{font-size:1.6rem;font-weight:700;color:var(--accent);font-family:'DM Mono',monospace;}
.stat-lbl{font-size:0.78rem;color:var(--muted);margin-top:2px;}

/* SECTION COMMON */
section{padding:6rem 2rem;}
.container{max-width:1200px;margin:0 auto;}
.section-tag{font-size:0.75rem;font-weight:600;color:var(--accent);letter-spacing:0.12em;text-transform:uppercase;margin-bottom:0.75rem;display:block;}
.section-title{font-size:clamp(1.8rem,3.5vw,2.6rem);font-weight:700;letter-spacing:-0.02em;margin-bottom:1rem;}
.section-sub{color:var(--muted);font-size:1rem;line-height:1.7;max-width:560px;}

/* ABOUT */
#about{background:var(--bg2);}
.about-grid{display:grid;grid-template-columns:1fr 1fr;gap:4rem;align-items:start;margin-top:3rem;}
.about-text p{color:var(--muted);line-height:1.8;margin-bottom:1rem;font-size:0.97rem;}
.about-text p strong{color:var(--text);}
.tech-stack{margin-top:1.5rem;}
.tech-stack-title{font-size:0.8rem;font-weight:600;color:var(--muted);letter-spacing:0.1em;text-transform:uppercase;margin-bottom:0.75rem;}
.tech-badges{display:flex;flex-wrap:wrap;gap:0.5rem;}
.badge{background:var(--bg3);border:1px solid var(--border);color:var(--text);padding:0.35rem 0.8rem;border-radius:6px;font-size:0.82rem;font-family:'DM Mono',monospace;}
.about-cards{display:flex;flex-direction:column;gap:1rem;}
.info-card{background:var(--card);border:1px solid var(--border);border-radius:12px;padding:1.25rem 1.5rem;}
.info-card-icon{font-size:1.5rem;margin-bottom:0.75rem;}
.info-card h4{font-size:0.95rem;font-weight:600;margin-bottom:0.4rem;}
.info-card p{font-size:0.85rem;color:var(--muted);line-height:1.6;}

/* SKILLS */
#skills{background:var(--bg);}
.skills-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:1.5rem;margin-top:3rem;}
.skill-card{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:1.75rem;transition:border-color 0.25s,transform 0.25s;}
.skill-card:hover{border-color:var(--accent);transform:translateY(-3px);}
.skill-icon{width:48px;height:48px;border-radius:10px;background:rgba(0,229,160,0.1);display:flex;align-items:center;justify-content:center;margin-bottom:1rem;font-size:1.5rem;}
.skill-name{font-size:1rem;font-weight:600;margin-bottom:0.5rem;}
.skill-desc{font-size:0.85rem;color:var(--muted);line-height:1.6;margin-bottom:1rem;}
.skill-bar-wrap{height:4px;background:var(--bg3);border-radius:4px;overflow:hidden;}
.skill-bar{height:100%;background:linear-gradient(90deg,var(--accent),var(--accent2));border-radius:4px;}

/* PACKAGES */
#packages{background:var(--bg2);}
.packages-intro{color:var(--muted);margin-top:0.75rem;font-size:0.97rem;line-height:1.7;}
.pkg-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:1.5rem;margin-top:3rem;}
.pkg-card{background:var(--card);border:1px solid var(--border);border-radius:14px;overflow:hidden;}
.pkg-header{padding:1.25rem 1.5rem;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:12px;}
.pkg-logo{width:36px;height:36px;object-fit:contain;border-radius:6px;}
.pkg-logo-placeholder{width:36px;height:36px;border-radius:6px;display:flex;align-items:center;justify-content:center;font-weight:700;font-size:0.75rem;color:#fff;}
.pkg-title{font-size:1rem;font-weight:600;}
.pkg-subtitle{font-size:0.8rem;color:var(--muted);}
.pkg-items{padding:1.25rem 1.5rem;}
.pkg-item{display:flex;align-items:flex-start;gap:10px;padding:0.5rem 0;border-bottom:1px solid rgba(42,42,58,0.5);cursor:pointer;}
.pkg-item:last-child{border-bottom:none;}
.pkg-checkbox{width:18px;height:18px;border-radius:4px;border:1.5px solid var(--border);flex-shrink:0;margin-top:1px;display:flex;align-items:center;justify-content:center;transition:all 0.2s;cursor:pointer;}
.pkg-checkbox.checked{background:var(--accent);border-color:var(--accent);}
.pkg-checkbox.checked::after{content:'✓';color:#0a0a0f;font-size:11px;font-weight:700;}
.pkg-item-label{font-size:0.85rem;color:var(--muted);transition:color 0.2s;}
.pkg-item.selected .pkg-item-label{color:var(--text);}
.pkg-footer{padding:1rem 1.5rem;border-top:1px solid var(--border);}
.pkg-order-btn{width:100%;background:transparent;border:1px solid var(--accent);color:var(--accent);padding:0.6rem 1rem;border-radius:8px;font-size:0.88rem;font-weight:600;cursor:pointer;transition:all 0.2s;font-family:'Space Grotesk',sans-serif;}
.pkg-order-btn:hover{background:var(--accent);color:#0a0a0f;}

/* CONTACT MODAL */
.modal-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:2000;align-items:center;justify-content:center;}
.modal-overlay.open{display:flex;}
.modal{background:var(--bg2);border:1px solid var(--border);border-radius:16px;padding:2rem;max-width:480px;width:90%;position:relative;}
.modal h3{font-size:1.2rem;font-weight:700;margin-bottom:0.5rem;}
.modal p{color:var(--muted);font-size:0.9rem;margin-bottom:1.5rem;}
.modal-close{position:absolute;top:1rem;right:1rem;background:none;border:none;color:var(--muted);font-size:1.4rem;cursor:pointer;line-height:1;}
.contact-options{display:flex;flex-direction:column;gap:0.75rem;}
.contact-opt{display:flex;align-items:center;gap:12px;padding:0.85rem 1rem;border-radius:10px;border:1px solid var(--border);text-decoration:none;color:var(--text);transition:border-color 0.2s,background 0.2s;}
.contact-opt:hover{border-color:var(--accent);background:rgba(0,229,160,0.05);}
.contact-opt-icon{width:36px;height:36px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:1.1rem;flex-shrink:0;}
.contact-opt-label{font-size:0.9rem;font-weight:500;}
.contact-opt-sub{font-size:0.78rem;color:var(--muted);}

/* SERVICES */
#services{background:var(--bg);}
.services-intro{color:var(--muted);font-size:0.97rem;line-height:1.7;margin-top:0.5rem;}
.services-tabs{display:flex;gap:0.5rem;flex-wrap:wrap;margin-top:2rem;}
.stab{padding:0.45rem 1rem;border-radius:6px;border:1px solid var(--border);font-size:0.82rem;font-weight:500;cursor:pointer;background:transparent;color:var(--muted);transition:all 0.2s;font-family:'Space Grotesk',sans-serif;}
.stab.active,.stab:hover{background:var(--accent);color:#0a0a0f;border-color:var(--accent);}
.services-content{margin-top:1.5rem;}
.services-panel{display:none;}
.services-panel.active{display:block;}
.services-panel-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:1rem;}
.svc-item{background:var(--card);border:1px solid var(--border);border-radius:10px;padding:1rem 1.25rem;display:flex;align-items:flex-start;gap:10px;}
.svc-num{font-family:'DM Mono',monospace;font-size:0.78rem;color:var(--accent);min-width:24px;margin-top:1px;}
.svc-text{font-size:0.88rem;line-height:1.5;color:var(--muted);}
.kra-box{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:2rem;margin-top:2rem;}
.kra-box h4{font-size:1.1rem;font-weight:600;margin-bottom:0.75rem;color:var(--accent);}
.kra-box p{color:var(--muted);font-size:0.9rem;line-height:1.7;margin-bottom:0.75rem;}
.kra-items{display:flex;flex-wrap:wrap;gap:0.5rem;margin-bottom:1rem;}
.kra-item{background:rgba(0,229,160,0.1);border:1px solid rgba(0,229,160,0.2);color:var(--accent);padding:0.35rem 0.85rem;border-radius:20px;font-size:0.82rem;}

/* CONTACT SECTION */
#contact{background:var(--bg2);}
.contact-grid{display:grid;grid-template-columns:1fr 1fr;gap:4rem;margin-top:3rem;}
.contact-info h3{font-size:1.2rem;font-weight:600;margin-bottom:1rem;}
.contact-info p{color:var(--muted);font-size:0.9rem;line-height:1.7;margin-bottom:1.5rem;}
.contact-links{display:flex;flex-direction:column;gap:0.75rem;}
.clink{display:flex;align-items:center;gap:12px;padding:0.85rem 1rem;border-radius:10px;border:1px solid var(--border);text-decoration:none;color:var(--text);transition:all 0.2s;}
.clink:hover{border-color:var(--accent);transform:translateX(4px);}
.clink-icon{width:40px;height:40px;border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:1.2rem;flex-shrink:0;}
.contact-form{display:flex;flex-direction:column;gap:1rem;}
.form-group{display:flex;flex-direction:column;gap:6px;}
.form-group label{font-size:0.82rem;font-weight:500;color:var(--muted);}
.form-group input,.form-group textarea{background:var(--card);border:1px solid var(--border);border-radius:8px;padding:0.75rem 1rem;color:var(--text);font-family:'Space Grotesk',sans-serif;font-size:0.9rem;outline:none;transition:border-color 0.2s;resize:vertical;}
.form-group input:focus,.form-group textarea:focus{border-color:var(--accent);}
.form-group textarea{min-height:120px;}
.form-submit{background:var(--accent);color:#0a0a0f;border:none;border-radius:8px;padding:0.85rem 2rem;font-weight:700;font-size:0.95rem;cursor:pointer;font-family:'Space Grotesk',sans-serif;transition:opacity 0.2s;}
.form-submit:hover{opacity:0.85;}

/* FOOTER */
footer{background:var(--bg);border-top:1px solid var(--border);padding:2.5rem 2rem;text-align:center;}
.footer-inner{max-width:1200px;margin:0 auto;}
.footer-logo{font-size:1.2rem;font-weight:700;color:var(--accent);margin-bottom:0.75rem;}
.footer-text{color:var(--muted);font-size:0.85rem;}
.footer-social{display:flex;gap:1rem;justify-content:center;margin-top:1.25rem;}
.fsoc{width:36px;height:36px;border-radius:8px;border:1px solid var(--border);display:flex;align-items:center;justify-content:center;color:var(--muted);text-decoration:none;font-size:0.9rem;transition:all 0.2s;}
.fsoc:hover{border-color:var(--accent);color:var(--accent);}

/* PROJECTS */
#projects{background:var(--bg2);}
.proj-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:1.5rem;margin-top:3rem;}
.proj-card{background:var(--card);border:1px solid var(--border);border-radius:14px;padding:1.5rem;transition:border-color 0.25s,transform 0.25s;}
.proj-card:hover{border-color:var(--accent2);transform:translateY(-2px);}
.proj-tag{font-size:0.72rem;font-weight:600;color:var(--accent2);letter-spacing:0.1em;text-transform:uppercase;margin-bottom:0.5rem;}
.proj-card h4{font-size:1rem;font-weight:600;margin-bottom:0.5rem;}
.proj-card p{font-size:0.85rem;color:var(--muted);line-height:1.6;}
.proj-techs{display:flex;flex-wrap:wrap;gap:0.4rem;margin-top:0.75rem;}
.proj-tech{font-size:0.72rem;background:var(--bg3);border:1px solid var(--border);border-radius:4px;padding:2px 8px;color:var(--muted);font-family:'DM Mono',monospace;}

/* RESPONSIVE */
@media(max-width:768px){
  .hero-inner{grid-template-columns:1fr;gap:2rem;}
  .hero-img{order:-1;}
  .hero-img img{aspect-ratio:16/9;max-height:320px;}
  .about-grid{grid-template-columns:1fr;}
  .contact-grid{grid-template-columns:1fr;}
  .nav-links,.nav-cta{display:none;}
  .hamburger{display:flex;}
  .mobile-menu.open{display:block;}
  .hero-stats{gap:1.25rem;}
  .stat-num{font-size:1.3rem;}
}
@media(max-width:480px){
  section{padding:4rem 1.25rem;}
  nav{padding:0 1.25rem;}
  .modal{padding:1.5rem;}
}
</style>
</head>
<body>

<!-- NAV -->
<nav>
  <div class="nav-inner">
    <a href="#home" class="logo">BRITON<span>.</span></a>
    <ul class="nav-links">
      <li><a href="#home">Home</a></li>
      <li><a href="#about">About</a></li>
      <li><a href="#skills">Skills</a></li>
      <li><a href="#packages">Packages</a></li>
      <li><a href="#services">Services</a></li>
      <li><a href="#projects">Projects</a></li>
      <li><a href="#contact">Contact</a></li>
    </ul>
    <a href="#contact" class="nav-cta">Hire Me</a>
    <button class="hamburger" onclick="toggleMenu()" aria-label="Menu">
      <span></span><span></span><span></span>
    </button>
  </div>
</nav>
<div class="mobile-menu" id="mobileMenu">
  <a href="#home" onclick="closeMenu()">Home</a>
  <a href="#about" onclick="closeMenu()">About</a>
  <a href="#skills" onclick="closeMenu()">Skills</a>
  <a href="#packages" onclick="closeMenu()">Packages</a>
  <a href="#services" onclick="closeMenu()">Services</a>
  <a href="#projects" onclick="closeMenu()">Projects</a>
  <a href="#contact" onclick="closeMenu()">Contact</a>
</div>

<!-- HERO -->
<section id="home">
  <div class="hero-bg"></div>
  <div class="hero-inner">
    <div>
      <div class="hero-label">&#x1F7E2; Available for work</div>
      <h1>Hi, I'm <span class="name">BRITON</span><br/><span class="role">Frontend Developer</span></h1>
      <p class="hero-desc">I build responsive, modern websites and powerful Microsoft Office solutions that help students, businesses, and organizations grow through technology.</p>
      <div class="hero-btns">
        <a href="#" class="btn-primary" id="downloadCVBtn">&#x2B07; Download CV</a>
        <a href="#contact" class="btn-outline">&#x1F4AC; Contact Me</a>
      </div>
      <div class="hero-stats">
        <div class="stat"><div class="stat-num">4+</div><div class="stat-lbl">Years Experience</div></div>
        <div class="stat"><div class="stat-num">12+</div><div class="stat-lbl">Projects Done</div></div>
        <div class="stat"><div class="stat-num">50+</div><div class="stat-lbl">Services Offered</div></div>
      </div>
    </div>
    <div class="hero-img">
      <img id="heroImg" src="" alt="BRITON - Frontend Developer at BritonCode"/>
    </div>
  </div>
</section>

<!-- ABOUT -->
<section id="about">
  <div class="container">
    <span class="section-tag">About Me</span>
    <h2 class="section-title">Frontend Developer &amp; IT Professional</h2>
    <div class="about-grid">
      <div class="about-text">
        <p>I'm <strong>BRITON</strong>, a dedicated and self-motivated <strong>Frontend Developer</strong> with over 4 years of experience building modern web interfaces and powerful digital solutions.</p>
        <p>I specialize in crafting <strong>responsive websites</strong> using HTML5, CSS3, and JavaScript — turning ideas into fast, beautiful, and user-friendly digital experiences. Whether it's a portfolio site, a business landing page, or a full e-commerce platform, I build it clean and pixel-perfect.</p>
        <p>Beyond web development, I'm a skilled <strong>Microsoft Office specialist</strong> — creating professional document systems, database applications, spreadsheet tools, and stunning presentations for businesses, schools, and individuals across Kenya.</p>
        <p>I'm based in <strong>Kenya</strong>, and I'm passionate about using technology to solve real-world problems — one project at a time.</p>
        <div class="tech-stack">
          <div class="tech-stack-title">Core Technologies</div>
          <div class="tech-badges">
            <span class="badge">HTML5</span>
            <span class="badge">CSS3</span>
            <span class="badge">JavaScript</span>
            <span class="badge">MS Word</span>
            <span class="badge">MS Excel</span>
            <span class="badge">MS Access</span>
            <span class="badge">PowerPoint</span>
            <span class="badge">Publisher</span>
          </div>
        </div>
      </div>
      <div class="about-cards">
        <div class="info-card">
          <div class="info-card-icon">&#x1F4BB;</div>
          <h4>Frontend Development</h4>
          <p>Responsive websites built with modern HTML5, CSS3, and vanilla JavaScript. Clean code, fast load times, mobile-first designs.</p>
        </div>
        <div class="info-card">
          <div class="info-card-icon">&#x1F4CA;</div>
          <h4>Office Solutions</h4>
          <p>Professional systems in Word, Excel, Access, PowerPoint, and Publisher — from grade trackers to hospital management systems.</p>
        </div>
        <div class="info-card">
          <div class="info-card-icon">&#x1F1F0;&#x1F1EA;</div>
          <h4>Government Services</h4>
          <p>KRA PIN registration, student online registration, email setup, and government service guidance at affordable rates.</p>
        </div>
        <div class="info-card">
          <div class="info-card-icon">&#x1F91D;</div>
          <h4>Student &amp; Business Support</h4>
          <p>Helping students complete registrations, and assisting small businesses with digital tools that improve efficiency.</p>
        </div>
      </div>
    </div>
  </div>
</section>

<!-- SKILLS -->
<section id="skills">
  <div class="container">
    <span class="section-tag">My Skills</span>
    <h2 class="section-title">What I Work With</h2>
    <p class="section-sub">A blend of web development and Microsoft Office expertise — tools that solve real problems for real people.</p>
    <div class="skills-grid">
      <div class="skill-card">
