  const msg = `Hello BRITON!\n\nName: ${name}\nContact: ${contact}\nService: ${service}\n\nMessage: ${message}`;
  window.open(`https://wa.me/${WHATSAPP}?text=${encodeURIComponent(msg)}`, '_blank');
}
</script>